(window.courseContentFiles = window.courseContentFiles || {})["000003/0015"] = "<!DOCTYPE html>\n<html lang=\"bg\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>document</title>\n  <link rel=\"stylesheet\" href=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.css\">\n  <style>\n    body {\n      font-family: \"Open Sans\", Arial, sans-serif;\n      max-width: 1550px;\n      margin: 0.5rem auto;\n      padding: 0 1rem;\n      line-height: 1.6;\n      color: #1f2937;\n    }\n    h1, h2, h3, h4 {\n      font-weight: 600;\n      margin-top: 0.7em;\n      margin-bottom: 0;\n      color: #588157;\n      line-height: 1.3;\n    }\n    h1 { font-size: 1.65em; }\n    h2 { font-size: 1.3em; }\n    h3 { font-size: 1.1em; margin-bottom: 0; }\n    h4 { font-size: 1.05em; margin-bottom: 0; }\n    h1 + h2, h1 + h3, h1 + h4, h2 + h3, h2 + h4, h3 + h4 { margin-top: 0; }\n    p {\n      margin: 0.3em 0;\n      white-space: pre-wrap;\n    }\n    p + p {\n      margin-top: 0.55em;\n    }\n    hr {\n      margin: 0.45em 0 0.2em;\n    }\n    hr + h1,\n    hr + h2,\n    hr + h3,\n    hr + h4 {\n      margin-top: 0.2em;\n    }\n    hr + p,\n    hr + ul,\n    hr + ol,\n    hr + blockquote,\n    hr + pre,\n    hr + table {\n      margin-top: 0.08em;\n    }\n    p + ul, p + ol { margin-top: 0.2em; }\n    h1 + p, h2 + p, h3 + p, h4 + p,\n    h1 + ul, h2 + ul, h3 + ul, h4 + ul,\n    h1 + ol, h2 + ol, h3 + ol, h4 + ol {\n      margin-top: 0;\n    }\n    h1 + table, h2 + table, h3 + table, h4 + table {\n      margin-top: -0.2em;\n    }\n    ul, ol {\n      margin: 0.2em 0;\n      padding-left: 1.5em;\n      list-style-position: outside;\n    }\n    li { margin: 0.2em 0; }\n    li p {\n      margin: 0;\n      padding: 0;\n      display: inline;\n    }\n    li > ul, li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    ul ul, ul ol, ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    ul ul { list-style-type: circle; }\n    ul ul ul { list-style-type: square; }\n    strong { font-weight: 600; }\n    em { font-style: italic; }\n    code {\n      background: rgba(218, 215, 205, 0.3);\n      padding: 2px 6px;\n      border-radius: 3px;\n      font-family: \"Courier New\", monospace;\n      font-size: 0.9em;\n    }\n    pre {\n      background: rgba(255, 255, 255, 0.5);\n      padding: 12px;\n      border-radius: 4px;\n      overflow-x: auto;\n      margin: 0.5em 0;\n      font-family: \"Courier New\", monospace;\n    }\n    pre code {\n      background: none;\n      padding: 0;\n    }\n    blockquote {\n      border-left: 3px solid #588157;\n      padding-left: 1em;\n      margin: 0.5em 0;\n      font-style: italic;\n      color: #166534;\n    }\n    table {\n      border-collapse: collapse;\n      margin: 0.75em 0;\n      width: 100%;\n      table-layout: auto;\n    }\n    th, td {\n      border: 1px solid rgba(2, 2, 2, 0.2);\n      padding: 6px 10px;\n      text-align: left;\n      vertical-align: top;\n      height: 24px;\n      line-height: 1.2;\n    }\n    thead th {\n      background: rgba(88, 129, 87, 0.13);\n      font-weight: 600;\n    }\n    tbody tr:nth-child(odd) {\n      background: rgba(88, 129, 87, 0.06);\n    }\n    /* Image alignment rules for exported content and md-viewer */\n    img[data-align=\"left\"] {\n      display: block;\n      margin: 8px auto 8px 0;\n    }\n    img[data-align=\"center\"] {\n      display: block;\n      margin: 8px auto;\n    }\n    img[data-align=\"right\"] {\n      display: block;\n      margin: 8px 0 8px auto;\n    }\n    .audio-link-inline {\n      display: inline-flex;\n      align-items: center;\n      gap: 7px;\n      margin: 0.2em 0;\n      max-width: 100%;\n      vertical-align: middle;\n      padding: 5px 7px;\n      border: 1px solid #d8e5d4;\n      border-radius: 9px;\n      background: #f4f9f2;\n    }\n    .audio-link-icon {\n      width: 26px;\n      height: 26px;\n      border: 1px solid #588157;\n      border-radius: 8px !important;\n      background: transparent;\n      color: #2f5d50;\n      cursor: pointer;\n      line-height: 1;\n      display: inline-flex;\n      align-items: center;\n      justify-content: center;\n      flex: 0 0 26px;\n      padding: 0;\n      text-align: center;\n      font-size: 12px;\n      font-weight: 700;\n    }\n    .audio-link-icon img,\n    .audio-time {\n      display: none !important;\n    }\n    .audio-link-label {\n      max-width: 125px;\n      min-width: 0;\n      font-size: 0.82em;\n      font-weight: 700;\n      overflow: hidden;\n      text-overflow: ellipsis;\n      white-space: nowrap;\n    }\n    .audio-link-label:empty {\n      display: none;\n    }\n    .audio-progress {\n      width: 118px;\n      accent-color: #588157;\n      cursor: pointer;\n    }\n    .audio-volume {\n      width: 44px;\n      accent-color: #588157;\n      cursor: pointer;\n    }\n    .audio-progress,\n    .audio-volume {\n      height: 4px;\n      appearance: none;\n      -webkit-appearance: none;\n      background: transparent;\n    }\n    .audio-link-inline audio {\n      display: none;\n    }\n    a {\n      color: inherit; /* Changed to inherit */\n      text-decoration: underline;\n    }\n    a:hover {\n      color: #74b673;\n    }\n    /* Keep <p> tags inside list items on same line (as they appear in editor) */\n    li p {\n      margin: 0 !important;\n      padding: 0 !important;\n      display: inline !important;\n    }\n    /* Prevent nested list paragraph issues */\n    li > ul,\n    li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    /* Ensure list structure is clean */\n    ul ul, ul ol,\n    ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    @media (max-width: 900px) {\n      body {\n        margin: 0.5rem 0;\n        padding: 0 0.5rem;\n        font-size: 16px;\n      }\n      h1 { font-size: 1.65em; }\n      h2 { font-size: 1.3em; }\n      h3 { font-size: 1.1em; }\n      p { margin: 0.3em 0; }\n      p + p { margin-top: 0.55em; }\n      ul, ol { padding-left: 1.5em; }\n      li { margin: 0.2em 0; }\n      table { font-size: 0.9em; }\n      th, td { padding: 6px 10px; }\n    }\n    .editor-note {\n      text-decoration: underline dotted #a3b18a;\n      text-decoration-thickness: 2px;\n      text-underline-offset: 2px;\n      text-decoration-skip-ink: none;\n      cursor: help;\n      position: relative;\n    }\n    .note-tooltip {\n      display: none;\n      position: absolute;\n      background-color: #f0f7f0;\n      color: #1f2937;\n      border: 1px solid #588157;\n      border-radius: 4px;\n      padding: 8px 12px;\n      width: fit-content;\n      max-width: min(700px, calc(100vw - 20px));\n      max-height: calc(100vh - 20px);\n      overflow: auto;\n      box-sizing: border-box;\n      box-shadow: 0 2px 8px rgba(0,0,0,0.2);\n      z-index: 10000;\n      font-size: 0.9em;\n      line-height: 1.4;\n      word-wrap: break-word;\n    }\n    .note-tooltip ul, .note-tooltip ol {\n      margin: 0 !important;\n      padding-left: 20px !important;\n    }\n    .note-tooltip li {\n      margin: 0 0 0.1em 0 !important;\n      padding: 0 !important;\n      line-height: 1.2 !important;\n    }\n    .note-tooltip li:last-child {\n      margin-bottom: 0 !important;\n    }\n    .note-tooltip .note-table-scroll {\n      overflow-x: hidden;\n      margin: 0.3em 0;\n      max-width: 100%;\n    }\n    .note-tooltip table {\n      border-collapse: collapse;\n      width: 100%;\n      max-width: 100%;\n      min-width: 0;\n      table-layout: fixed;\n      background: #ffffff;\n    }\n    .note-tooltip th,\n    .note-tooltip td {\n      border: 1px solid rgba(88, 129, 87, 0.35);\n      padding: 4px 8px;\n      text-align: left;\n      vertical-align: top;\n      line-height: 1.3;\n      white-space: normal;\n      overflow-wrap: anywhere;\n      word-break: break-word;\n    }\n    .note-tooltip thead th {\n      background: rgba(88, 129, 87, 0.12);\n      font-weight: 600;\n    }\n  </style>\n  <script>\n    document.addEventListener('DOMContentLoaded', function() {\n      const tooltip = document.createElement('div');\n      tooltip.className = 'note-tooltip';\n      document.body.appendChild(tooltip);\n\n      function parseNoteMarkdown(text) {\n        if (!text) return '';\n\n        const splitTableCells = function(line) {\n          return String(line || '')\n            .trim()\n            .replace(/^\\|/, '')\n            .replace(/\\|$/, '')\n            .split('|')\n            .map(function(cell) { return cell.trim(); });\n        };\n\n        const isTableSeparatorLine = function(line) {\n          const cells = splitTableCells(line);\n          return cells.length > 0 && cells.every(function(cell) {\n            return /^:?-{3,}:?$/.test(cell);\n          });\n        };\n\n        const getTableAlignment = function(cell) {\n          if (/^:-{3,}:$/.test(cell)) return 'center';\n          if (/^-{3,}:$/.test(cell)) return 'right';\n          if (/^:-{3,}$/.test(cell)) return 'left';\n          return '';\n        };\n\n        let lines = text.split('\\n');\n        let html = [];\n        let stack = [];\n\n        for (let i = 0; i < lines.length; i++) {\n          let line = lines[i];\n\n          let indentMatch = line.match(/^(\\s*)/);\n          let indent = indentMatch ? indentMatch[1].length : 0;\n          let content = line.trim();\n\n          const nextLine = i + 1 < lines.length ? lines[i + 1].trim() : '';\n          const maybeTableHeader = content.includes('|') && splitTableCells(content).length >= 2;\n          const maybeTableSeparator = nextLine.includes('|') && isTableSeparatorLine(nextLine);\n\n          if (maybeTableHeader && maybeTableSeparator) {\n            while (stack.length > 0) {\n              let closed = stack.pop();\n              html.push('</' + closed.type + '>');\n            }\n\n            const headerCells = splitTableCells(content);\n            const alignCells = splitTableCells(nextLine);\n\n            html.push('<div class=\"note-table-scroll\"><table><thead><tr>');\n            headerCells.forEach(function(cell, idx) {\n              const align = getTableAlignment(alignCells[idx] || '');\n              const alignAttr = align ? ' style=\"text-align:' + align + ';\"' : '';\n              html.push('<th' + alignAttr + '>' + cell + '</th>');\n            });\n            html.push('</tr></thead><tbody>');\n\n            i += 2;\n            while (i < lines.length) {\n              const rowLine = lines[i].trim();\n              if (!rowLine || !rowLine.includes('|')) break;\n              if (isTableSeparatorLine(rowLine)) {\n                i++;\n                continue;\n              }\n\n              const rowCells = splitTableCells(rowLine);\n              if (rowCells.length === 0) {\n                i++;\n                continue;\n              }\n\n              html.push('<tr>');\n              rowCells.forEach(function(cell, idx) {\n                const align = getTableAlignment(alignCells[idx] || '');\n                const alignAttr = align ? ' style=\"text-align:' + align + ';\"' : '';\n                html.push('<td' + alignAttr + '>' + cell + '</td>');\n              });\n              html.push('</tr>');\n              i++;\n            }\n\n            html.push('</tbody></table></div>');\n            i--;\n            continue;\n          }\n\n          let isUl = /^[-*]\\s+(.+)/.test(content);\n          let isOl = /^\\d+\\.\\s+(.+)/.test(content);\n\n          if (isUl || isOl) {\n            let listType = isUl ? 'ul' : 'ol';\n            let match = isUl ? content.match(/^[-*]\\s+(.+)/) : content.match(/^\\d+\\.\\s+(.+)/);\n            let itemText = match[1];\n\n            if (stack.length === 0) {\n              stack.push({ type: listType, indent: indent });\n              html.push('<' + listType + '>');\n            } else {\n              let last = stack[stack.length - 1];\n\n              if (indent > last.indent) {\n                stack.push({ type: listType, indent: indent });\n                html.push('<' + listType + '>');\n              } else if (indent < last.indent) {\n                while (stack.length > 0 && stack[stack.length - 1].indent > indent) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                }\n                if (stack.length === 0 || stack[stack.length - 1].indent !== indent) {\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                } else if (stack[stack.length - 1].type !== listType) {\n                   let closed = stack.pop();\n                   html.push('</' + closed.type + '>');\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                }\n              } else {\n                if (last.type !== listType) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                  stack.push({ type: listType, indent: indent });\n                  html.push('<' + listType + '>');\n                }\n              }\n            }\n            html.push('<li>' + itemText + '</li>');\n          } else {\n            if (content !== '') {\n               while (stack.length > 0) {\n                 let closed = stack.pop();\n                 html.push('</' + closed.type + '>');\n               }\n            }\n            if (/^(?:---|\\*\\*\\*|___)$/.test(content)) {\n              html.push('<hr>');\n            } else if (/^#{1,4}\\s+/.test(content)) {\n              const headingMatch = content.match(/^(#{1,4})\\s+(.+)$/);\n              if (headingMatch) {\n                const level = headingMatch[1].length;\n                html.push('<h' + level + '>' + headingMatch[2] + '</h' + level + '>');\n              }\n            } else if (content) {\n              html.push(content + '<br>');\n            } else {\n              html.push('<br>');\n            }\n          }\n        }\n\n        while (stack.length > 0) {\n          let closed = stack.pop();\n          html.push('</' + closed.type + '>');\n        }\n\n        let result = html.join('')\n          .replace(/!\\[(.*?)\\]\\((.*?)\\)/g, '<img src=\"$2\" alt=\"$1\">')\n          .replace(/\\*\\*(.+?)\\*\\*/g, '<strong>$1</strong>')\n          .replace(/__(.+?)__/g, '<strong>$1</strong>')\n          .replace(/\\*(.+?)\\*/g, '<em>$1</em>')\n          .replace(/_(.+?)_/g, '<em>$1</em>')\n          .replace(/`(.+?)`/g, '<code>$1</code>')\n          .replace(/\\[(.+?)\\]\\((.+?)\\)/g, '<a href=\"$2\" target=\"_blank\">$1</a>');\n\n        result = result\n          .replace(/<br><ul>/g, '<ul>')\n          .replace(/<br><ol>/g, '<ol>')\n          .replace(/</ul><br>/g, '</ul>')\n          .replace(/</ol><br>/g, '</ol>');\n\n        return result;\n      }\n\n      document.body.addEventListener('mouseover', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          const note = e.target.dataset.note;\n          if (note) {\n            tooltip.innerHTML = parseNoteMarkdown(note);\n            tooltip.style.display = 'block';\n            const rect = e.target.getBoundingClientRect();\n            const tooltipRect = tooltip.getBoundingClientRect();\n            const pageX = window.scrollX || window.pageXOffset;\n            const pageY = window.scrollY || window.pageYOffset;\n            const maxLeft = pageX + window.innerWidth - tooltipRect.width - 10;\n            const minLeft = pageX + 10;\n\n            let left = rect.left + pageX;\n            if (left > maxLeft) left = maxLeft;\n            if (left < minLeft) left = minLeft;\n\n            let top = rect.bottom + pageY + 6;\n            const maxTop = pageY + window.innerHeight - tooltipRect.height - 10;\n            if (top > maxTop) {\n              top = rect.top + pageY - tooltipRect.height - 6;\n            }\n            if (top < pageY + 10) top = pageY + 10;\n\n            tooltip.style.left = left + 'px';\n            tooltip.style.top = top + 'px';\n          }\n        }\n      });\n\n      document.body.addEventListener('mouseout', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          setTimeout(() => {\n            if (!tooltip.matches(':hover')) {\n              tooltip.style.display = 'none';\n            }\n          }, 100);\n        }\n      });\n\n      tooltip.addEventListener('mouseleave', function() {\n        tooltip.style.display = 'none';\n      });\n    });\n  </script>\n</head>\n<body>\n<h1 style=\"text-align: center\">Тема 130. Заболявания на хипофизата. Синдром на Шихан. Безвкусен диабет.</h1><p><span class=\"editor-note\" data-note=\"# Анатомия\n**Хипофизната жлеза** е малка структура с бобовидна форма, разположена в основата на мозъка, в **sella turcica**. Тя е тясно свързана с хипоталамуса чрез свързваща дръжка, съдържаща аксонални влакна и богат венозен плексус, който формира **портална циркулация**.\nЖлезата тежи около **0,5 g** и има максимален диаметър около **15 mm**.\nХипофизата се състои от два морфологично и функционално различни компонента:\n* **аденохипофиза** — преден дял, изграден от секреторни клетки;\n* **неврохипофиза** — заден дял, представляващ продължение на хипоталамуса.\n**Аденохипофизата** е изградена от ацини, в които клетките, продуциращи различни хормони, са размесени. В нея се различават:\n* **ацидофилни клетки**;\n* **базофилни клетки**;\n* **хромофобни клетки**.\n# Физиология\nВ зрялата предна част на хипофизата се намират клетки, способни да продуцират:\n* **соматотропин** — **GH**;\n* **пролактин**;\n* **адренокортикотропин** — **ACTH**;\n* **тиреоидстимулиращ хормон** — **TSH**;\n* **гонадотропини** — **LH** и **FSH**.\n**Неврохипофизата** съдържа глиални клетки и нервни влакна. В нея се секретират хормони, синтезирани в хипоталамуса:\n* **окситоцин**;\n* **вазопресин**.\n**Окситоцинът** предизвиква контракция на гладката мускулатура на матката и участва в отделянето на мляко от млечната жлеза.\n**Вазопресинът** действа върху бъбреците, като концентрира урината, и има ефекти върху съдовата гладка мускулатура, тромбоцитната агрегация и освобождаването на **фактор VIII** и **von Willebrand factor**.\" id=\"note-1778876917417-1\" style=\"\"><span style=\"color: rgb(236, 105, 36)\">Анатомия и физиология.</span></span></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Патология</h2><p>Според нивото на засягане <strong>ендокринните нарушения</strong> се разделят на:</p><ol><li><strong>Първични</strong> — засяга се самата ендокринна жлеза.</li><li><strong>Вторични</strong> — таргетната жлеза е нормална, но функцията ѝ е нарушена поради неадекватни нива на <strong>тропните хормони</strong> от хипофизата.</li><li><strong>Третични</strong> — дължат се на <strong>хипоталамични нарушения</strong>, например <strong>краниофарингеом</strong>.</li></ol><p>Заболяванията на <strong>аденохипофизата</strong> могат да се проявят с <strong>хиперпитуитаризъм</strong>, <strong>хипопитуитаризъм</strong> или <strong>локални ефекти на притискане</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Хиперпитуитаризъм</h2><p><strong>Хиперпитуитаризъм</strong> означава повишена секреция на един или повече тропни хормони в предния дял на хипофизата.</p><p>Той може да засегне регулацията на:</p><ul><li><strong>растежа</strong>;</li><li><strong>лактацията</strong>;</li><li><strong>щитовидната жлеза</strong>;</li><li><strong>надбъбречната жлеза</strong>.</li></ul><p>Причините могат да бъдат:</p><ul><li><strong>аденом</strong>;</li><li>хиперплазия на хормон-продуциращите клетки;</li><li>злокачествен тумор — <strong>карцином</strong>;</li><li><strong>паранеопластичен синдром</strong>.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Хипопитуитаризъм</h2><p><strong>Хипопитуитаризмът</strong> обикновено възниква вследствие на деструктивни процеси, засягащи <strong>аденохипофизата</strong>.</p><p>Най-честите причини са:</p><ul><li><strong>несекретиращи аденоми</strong>;</li><li><strong>хипофизна некроза на Sheehan</strong>;</li><li><strong>синдром на празната sella</strong>.</li></ul><p>Тези три причини съставляват около <strong>90%</strong> от случаите на <strong>панхипопитуитаризъм</strong>.\nДруги възможни причини са:</p><ul><li>непитуитарни тумори в областта — първични или метастатични;</li><li>хирургични интервенции;</li><li>радиация;</li><li><strong>апоплексия</strong> — внезапни хеморагии;</li><li><strong>кисти на Rathke</strong>;</li><li>генетични дефекти;</li><li><strong>лимфоцитарен хипофизит</strong> — автоимунно заболяване.</li></ul><p>По-рядко хипофизната недостатъчност се проявява като изолиран, или <strong>монотропен</strong>, дефицит. Най-често <span class=\"editor-note\" data-note=\"### Липса на соматотропин\nПри възрастни липсата на **соматотропин** трудно се установява, освен чрез радиоимунологично изследване.\nПри деца в предпубертетна възраст тя води до симетрично забавяне на растежа — **хипофизен нанизъм**.\nТази форма трябва да се разграничава от **хипотиреоидизма** — **кретенизъм**. За кретенизма са характерни монголоидни черти на лицето и изразена умствена недоразвитост. При хипофизния нанизъм лицевите черти са нормални, а интелектът е съхранен.\" id=\"note-1778877568680-3\">липсва <strong>соматотропин</strong></span><strong></strong>, по-рядко се наблюдава <strong>гонадотропна недостатъчност</strong>, а още по-рядко — дефицит на <strong>ACTH</strong>. Тези еднохормонални липси често се свързват с увреждания главно в <strong>хипоталамуса</strong>, макар задоволително обяснение да липсва.</p><h3>Синдром на Sheehan</h3><p><strong>Синдромът на Sheehan</strong>, известен още като <strong>следродова хипофизна некроза</strong>, представлява исхемична некроза на <strong>аденохипофизата</strong> след раждане.</p><p>Развива се най-често след тежко раждане с обилен <strong>акушерски кръвоизлив</strong> или шок. С времето исхемичната тъкан се резорбира и се замества от <strong>фиброзна тъкан</strong>, в която може да се отложи и калций.</p><p>Синдромът се установява при:</p><ul><li><strong>8%</strong> от жените с умерена кръвозагуба;</li><li><strong>53%</strong> от жените с тежка кръвозагуба по време на раждане.</li></ul><p>Ранна проява е оскъдната или липсваща <strong>лактация</strong>, поради дефицит на <strong>пролактин</strong>.</p><p>По-късно постепенно се развиват:</p><ul><li><strong>адинамия</strong>;</li><li>намален апетит;</li><li><strong>хипотония</strong>;</li><li>намаление на млечните жлези;</li><li><strong>аменорея</strong>;</li><li>атрофия на гениталиите.</li></ul><p>Тези промени са свързани главно с <strong>гонадотропен дефицит</strong>. Съпътстващото намаляване на продукцията на <strong>TSH</strong> и <strong>ACTH</strong> може да доведе до:</p><ul><li><strong>хипотиреоидизъм</strong>;</li><li><strong>адренокортикална недостатъчност</strong>.</li></ul><p>Недостатъчността на тиреоидната функция се проявява по-късно, а <strong>надбъбречната недостатъчност</strong> — най-късно. Болните са с понижен тонус и склонност към депресия.</p><h3>Безвкусен диабет</h3><p><strong>Безвкусният диабет</strong> — <strong>diabetes insipidus</strong> — е израз на <strong>неврохипофизна недостатъчност</strong>.</p><p>Той се развива при засягане на неврохипофизата или хипоталамо-хипофизната област от:</p><ul><li>травми;</li><li>тумори;</li><li>възпаление;</li><li>хирургични процедури;</li><li><strong>луес</strong>;</li><li>карциномни метастази;</li><li>тумори на <strong>неврохипофизата</strong>.</li></ul><p>Механизмът е свързан с прекъсване на немиелиновите влакна в хипофизния тракт, най-често в областта на пода на третия вентрикул. Това води до дефицит на <strong>антидиуретичен хормон</strong>.</p><p>Отпадането на функцията на антидиуретичния хормон причинява невъзможност на бъбреците да концентрират урината. Клинично това се проявява с:</p><ul><li><strong>полиурия</strong>;</li><li><strong>полидипсия</strong>.</li></ul><p>Причина за безвкусен диабет могат да бъдат и <strong>хипоталамични супраселарни тумори</strong>, включително <strong>глиоми</strong> и <strong><span class=\"editor-note\" data-note=\"**Краниофарингеомите** са бавно нарастващи, добре отграничени тумори, често с кистична форма и размер около **3–4 cm**. Имат два възрастови пика:\n- **5–15 години**;\n- над **65 години**.\nРазличават се два типа:\n- **адамантинозен** — среща се при деца, с кисти и калцификати;\n- **папиларен** — без кератин, кисти и калцификати.\" id=\"note-1778877623830-4\">краниофарингеоми</span></strong>, произлизащи от джобчето на <strong>Rathke</strong>.</p><p>Тежките последствия на безвкусния диабет са свързани със загуба на вода и нарушения в <strong>минералната обмяна</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 131. Доброкачествени и злокачествени тумори на хипофизата. Акромегалия. Болест на Иценко-Кушинг.</h1><p>Туморите на <strong>предния дял на хипофизата</strong> обикновено са доброкачествени — <strong>аденоми</strong>, с ограничен растежен потенциал.</p><p>Въпреки че могат да имат белези на <strong>инвазивен растеж</strong> и да рецидивират, те много рядко метастазират в <strong>ЦНС</strong>, а още по-рядко — извън нея.</p><p>Хистологичните белези на малигненост, като:</p><ul><li>митотична активност;</li><li>некрози;</li><li>ядрен плеоморфизъм,</li></ul><p>нямат решаващо значение за биологичното поведение на хипофизните аденоми.</p><p>Терминът <strong>хипофизен карцином</strong> се използва само когато туморът е образувал <strong>метастази извън централната нервна система</strong>. </p><h2>Класификация на хипофизните аденоми</h2><p>Според хистологичната характеристика се различават три основни типа аденоми:</p><ol><li><strong>Еозинофилен аденом</strong> — изграден от големи полигонални клетки с ацидофилни гранули в цитоплазмата.</li><li><strong>Хромофобен аденом</strong> — съдържа малки закръглени клетки с бледорозова цитоплазма.</li><li><strong>Базофилен аденом</strong> — изграден от клетки с обилна <strong>PAS-позитивна базофилна цитоплазма</strong>.</li></ol><p>По-прецизната класификация се основава на <strong>имуноцитохимично доказване на хормонална продукция</strong>. Допълнително подразделяне може да се извърши чрез електронна микроскопия според големината и формата на секреторните гранули.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Соматотропиноми</h2><p><strong>Соматотропиномите</strong> са хипофизни аденоми, съставени от клетки, продуциращи <strong>соматотропин</strong>.</p><h3>Честота и локализация</h3><p>Те съставляват около <strong>12–15%</strong> от всички хипофизни тумори.</p><p>Повечето възникват в един от латералните дялове на хипофизата, където са разположени много <strong>соматотропни клетки</strong>.</p><h3>Клинична картина</h3><p>Водеща клинична проява е <strong>акромегалията</strong>, която се характеризира с нарастване на <strong>костите</strong> и <strong>меките тъкани</strong>, най-силно изразено в изпъкналите части на лицето и периферията на крайниците.</p><p>Характерни промени са:</p><ul><li>задебеляване на <strong>кожата</strong> и <strong>подкожната мастна тъкан</strong>;</li><li>груби черти на лицето;</li><li>уголемяване на <strong>носа</strong> и <strong>езика</strong>;</li><li>изпъкване на костите над и под орбитите;</li><li>задебеляване и удължаване на долната челюст — <strong>прогнатия</strong>;</li><li>раздалечаване на зъбите;</li><li>поява на бръчки, особено по лицето;</li><li>широки китки и стъпала;</li><li>дебели пръсти.</li></ul><p>Наблюдава се и <strong>спланхомегалия</strong> — увеличение на вътрешните органи. Най-често се установява <strong>кардиомегалия</strong>, която впоследствие може да доведе до <strong>хронична сърдечна недостатъчност</strong>.</p><p>Развива се и <strong>атрофия на половите жлези</strong>.</p><p>Когато <strong>хиперсоматотропизмът</strong> възникне при млади хора с незавършено вкостяване на епифизарните хрущяли, се развива <strong>гигантизъм</strong>. Ръстът първоначално нараства равномерно, но по-късно се появяват несъразмерности, характерни за акромегалията.</p><h3>Микроскопски промени</h3><p>Аденомите са изградени от <strong>еозинофилни клетки</strong>, които имуноцитохимично показват позитивна реакция за <strong>соматотропин</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>ACTH-продуциращи аденоми</h2><p>Аденомите, продуциращи <strong>адренокортикотропен хормон — ACTH</strong>, обикновено са свързани с <strong>болестта на Cushing</strong>.</p><p>При пациенти с предходна билатерална адреналектомия може да се развие <strong>синдром на Nelson</strong>.</p><h3>Честота</h3><p>Тези аденоми съставляват около <strong>9–15%</strong> от хипофизните тумори.</p><p><strong>Болестта на Cushing</strong> засяга предимно жени на възраст <strong>20–40 години</strong>. Съотношението жени:мъже е приблизително <strong>2:1</strong>.</p><h3>Клинична картина</h3><p>Болните с <strong>болест на Cushing</strong> имат патологичен тип затлъстяване, при което мастната тъкан се натрупва предимно в областта на:</p><ul><li><strong>шията</strong>;</li><li><strong>лицето</strong>;</li><li><strong>корема</strong>.</li></ul><p>Крайниците остават относително слабо засегнати.</p><p>Характерно е оформянето на <strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/Fenroll/2026-05-15/text-editor-images/2026/05/1778878390632-image.png &quot;width=100%&quot;)\" id=\"note-1778878469437-8\">facies lunata</span></strong>, което се дължи на отлагане на мастна тъкан в областта на лицето, <strong>плетора</strong> и <strong>хирзутизъм</strong> при жените.</p><p>Особено типични са <strong>дистрофичните кожни промени</strong>, свързани с намалено съдържание на колаген. Кожата изтънява, става по-прозрачна и съдовата мрежа се вижда по-ясно.</p><p>Почти при всички болни се наблюдават <strong><span class=\"editor-note\" data-note=\"За появата им допринасят:\n- изтъняването на кожата;\n- разширението на подкожните венозни плексуси;\n- кръвоизливите в субкутанната мастна тъкан.\" id=\"note-1778878463236-7\">кожни стрии</span></strong>. </p><p>Други характерни промени са:</p><ul><li><strong>генерализирана остеопороза</strong>;</li><li><strong>артериална хипертония</strong>;</li><li>хипертрофия и дилатация на <strong>лявата камера</strong>;</li><li>ранно и прогресивно развитие на <strong>генерализирана атеросклероза</strong>.</li></ul><p><strong>Съдовите усложнения</strong> често са причина за фатален изход. За развитието им значение имат <strong>артериалната хипертония</strong> и <strong>хиперлипопротеинемията</strong>.</p><h3>Макроскопски промени</h3><p>Активните ACTH-продуциращи тумори често са малки, понякога с размер само около <strong>1 mm</strong>.</p><p>В някои случаи на хипофизозависима болест на Cushing не се открива аденом. Тези случаи се свързват с хиперплазия на <strong>ACTH-продуциращите базофилни клетки</strong>.</p><h3>Микроскопски промени</h3><p>Аденомите при болестта на Cushing са най-често <strong>базофилни</strong>, по-рядко <strong>хромофобни</strong>.</p><p>В <strong>надбъбречните жлези</strong> често се установява хиперплазия, главно на:</p><ul><li><strong>zona fasciculata</strong>;</li><li><strong>zona reticularis</strong>,</li></ul><p>понякога с формиране на <strong>микроаденоматозни възли</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 132. Захарен диабет. Патогенеза, морфологична характеристика.</h1><p><strong>Захарният диабет</strong> — <strong>diabetes mellitus</strong> — е хронично заболяване, характеризиращо се с комплексно нарушение на <strong>въглехидратната</strong>, <strong>мастната</strong> и <strong>белтъчната обмяна</strong>, вследствие на абсолютна или относителна <strong>инсулинова недостатъчност</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Честота и разпространение</h2><p>Най-често заболяват лица на възраст <strong>40–60 години</strong>. Мъжете и жените се засягат почти еднакво.</p><h2>Етиология</h2><p>В около <strong>90%</strong> от случаите захарният диабет е <strong>наследствено обусловен</strong>. Генетичните фактори са свързани с някои антигени от системата <strong>HLA</strong>, локализирани в <strong>6-та хромозома</strong>.</p><p><strong>Вторичният</strong>, или придобит диабет, може да бъде свързан с:</p><ul><li>хронично-обструктивен панкреатит;</li><li>тумори;</li><li><strong>хемохроматоза</strong>;</li><li>склеротични промени в екзо-ендокринния панкреас;</li><li>заболявания на други жлези с вътрешна секреция.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Патогенеза на захарен диабет тип I</h2><p><strong>Захарен диабет тип I</strong> се развива в резултат на имунно-медиирано увреждане и разрушаване на <strong>β-клетките</strong> в Лангерхансовите острови, което води до <strong>абсолютна инсулинова недостатъчност</strong>.</p><p>Вирусните инфекции могат да участват в патогенезата чрез няколко механизма:</p><ol><li><strong>Директно увреждане на островчетата\n</strong>Вирусите могат директно да увредят Лангерхансовите острови, като освободят антигени от <strong>β-клетките</strong>. Това води до активиране на <strong>Т-клетки</strong>, които започват да атакуват собствените β-клетки.</li><li><strong>Молекулярна мимикрия\n</strong>Вирусните протеини могат да наподобяват антигени на собствените β-клетки. В резултат имунният отговор срещу вируса кръстосано реагира със собствената тъкан.</li><li><strong>Повторна инфекция със сроден вирус\n</strong>Ранно инфектиране може да бъде последвано от заразяване със сроден вирус със сходни епитопи, което допълнително активира автоимунния процес.</li></ol><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Клинична картина</h2><p>Клинично се разграничават два основни типа захарен диабет:</p><ol><li><strong>Инсулинозависим диабет</strong> — тип I.</li><li><strong>Неинсулинозависим диабет</strong> — тип II.</li></ol><h3>Инсулинозависим диабет — тип I</h3><p><strong>Инсулинозависимият диабет</strong> е характерен за детската и юношеската възраст.</p><p>Проявява се с т.нар. големи симптоми, свързани с тежки обменни нарушения:</p><ul><li><strong>полиурия</strong>;</li><li><strong>полидипсия</strong>;</li><li><strong>полифагия</strong>;</li><li>склонност към <strong>ацидоза</strong>.</li></ul><h3>Неинсулинозависим диабет — тип II</h3><p><strong>Неинсулинозависимият диабет</strong> често протича безсимптомно.</p><p>Значителна част от болните могат години наред да имат умерена <strong>хипергликемия</strong> без други оплаквания. При тях липсват катаболни прояви и обикновено няма склонност към развитие на <strong>кетоацидоза</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Морфология</h2><h3>Макроскопски промени</h3><p>Панкреасът може да бъде <strong>атрофичен</strong>, с намален обем и маса — около <strong>50–60 g</strong> вместо нормалните <strong>100–110 g</strong>.</p><p>При възрастни починали болни често се наблюдава разрастване на мастна и съединителна тъкан в интерстициума:</p><ul><li><strong>липоматоза</strong>;</li><li><strong>фиброза</strong>.</li></ul><h3>Микроскопски промени</h3><p>Измененията в <strong>островния апарат</strong> зависят от продължителността на заболяването.</p><p>Количеството на <strong>Лангерхансовите острови</strong> е редуцирано. Част от тях са:</p><ul><li>атрофични;</li><li>хиалинизирани;</li><li>обградени от концентрично разраснала колагенна тъкан.</li></ul><p>Откриват се и единични големи острови с увеличени размери, намиращи се в състояние на <strong>компенсаторна хипертрофия</strong>.</p><p>При болни с диабет тип I се наблюдава намаляване на количеството на <strong>β-клетките</strong>, докато <strong>α-</strong> и <strong>δ-клетките</strong> са непроменени или дори увеличени. В цитоплазмата на β-клетките понякога се установяват дистрофични промени със загуба на гранулациите и последваща атрофия.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Усложнения</h2><p>Най-честите и най-тежки усложнения, особено при продължително протичащ диабет, са локализирани в <strong>съдовата система</strong>. Развиват се:</p><ul><li><strong>макроангиопатия</strong>;</li><li><strong>микроангиопатия</strong>.</li></ul><h3>Макроангиопатия</h3><p>При около <strong>75%</strong> от възрастните болни с диабет се установява силно изразена <strong>атеросклероза</strong>.</p><p>Тя се развива по-рано, протича по-бързо и по-тежко в сравнение с недиабетици. Засяга предимно артерии от еластичен и еластично-мускулен тип, най-вече:</p><ul><li>коронарните артерии;</li><li>мозъчните артерии;</li><li>артериите на долните крайници.</li></ul><h3>Микроангиопатия</h3><p><strong>Диабетната микроангиопатия</strong> засяга микроциркулацията на:</p><ul><li>бъбреците;</li><li>ретината;</li><li>нервната система;</li><li>други органи.</li></ul><p>Открива се при около <strong>50%</strong> от диабетиците.</p><p>Най-голямо диагностично значение има <strong>ангиопатията на ретината</strong>. В началото се наблюдават разширяване и нагъване на капилярите, а във вените се появяват <strong>микроаневризми</strong>. По-късно съдовите стени хиалинизират, като често се установяват и <strong>кръвоизливи в ретината</strong>.</p><h3>Бъбречни усложнения</h3><p>В бъбреците микроангиопатията засяга гломерулните капиляри и води до <strong>интеркапилярна гломерулосклероза</strong>.</p><p>Тя може да бъде:</p><ul><li>дифузна;</li><li>нодуларна;</li><li>смесена.</li></ul><p>По-характерна е <strong>нодуларната форма</strong>, известна като <strong>синдром на Kimmelstiel–Wilson</strong>. При нея <strong>PAS-позитивна субстанция</strong> се отлага предимно в периферните бримки на гломерулите под формата на овални еозинофилни клъбца.</p><p>При диабетици често се установява <strong>хроничен пиелонефрит</strong>, понякога съчетан с <strong>некроза на папилите</strong>.</p><p><strong>Некротичният папилит</strong> е относително рядка, остра форма на пиелонефрит, характеризираща се с:</p><ul><li>исхемична некроза на бъбречните папили;</li><li>тромбоза на вените;</li><li>бурно протичаща инфекция.</li></ul><h3>Неврологични промени</h3><p>В предните и задните коренчета на гръбначния мозък и в периферните нерви се установяват:</p><ul><li>сегментна демиелинизация;</li><li>оток на Швановите обвивки.</li></ul><h3>Инфекциозни усложнения</h3><p>За диабетиците е характерна склонност към инфекциозни процеси, като:</p><ul><li>фурункулоза;</li><li>сепсис;</li><li>туберкулоза.</li></ul><p>Може да се наблюдава и <strong>алвеоларна пиорея</strong> с изпадане на зъбите.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Най-чести тежки усложнения</h2><p>Най-честите усложнения са свързани с <strong>макро- и микроангиопатиите</strong>:</p><ul><li><strong>инфаркт на миокарда</strong>;</li><li>мозъчен инфаркт;</li><li>гангрена на долните крайници;</li><li><strong>хронична бъбречна недостатъчност</strong>.</li></ul><p>Хроничната бъбречна недостатъчност може да се дължи както на <strong>гломерулосклероза</strong>, така и на <strong>хроничен пиелонефрит</strong>.</p><p>Тежко усложнение е <strong>диабетната кома</strong>, която може да доведе до смърт при неправилно или ненавременно лечение.</p><p>Смърт може да настъпи и вследствие на:</p><ul><li>сепсис;</li><li>пневмония;</li><li>друг тежък инфекциозен процес.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 133. Тумори на надбъбречните жлези. Видове, морфологична характеристика. Хиперадренализъм и адренална инсуфициенция.</h1><p>Неопластичните процеси в <strong>надбъбречните жлези</strong> се различават според произхода, структурата и функцията на двата им основни компонента:</p><ul><li><strong>кортикална част</strong>;</li><li><strong>медуларна част</strong>.</li></ul><p>В <strong>кората</strong> на надбъбречната жлеза, чиято активност се регулира от <strong>ACTH</strong> на аденохипофизата и от хипоталамуса, се наблюдава широк спектър от <strong>хиперпластични процеси</strong>, със или без функционална изява.</p><p>В <strong>медуларната част</strong> хиперпластичните процеси не са характерни, а неопластичните процеси са основната форма на клетъчна пролиферация.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Тумори на коровия слой на надбъбречните жлези</h2><h3>Доброкачествени тумори — аденоми</h3><p><strong>Аденомите на надбъбречната кора</strong> са доброкачествени тумори, които макроскопски се представят като ограничени жълтеникави възли с размер около <strong>1–2 cm</strong>.</p><p>Микроскопски аденомите показват структурни и цитологични особености на зоната, от която произхождат, но почти винаги съдържат и клетки от други зони на кората.</p><p>Характерни микроскопски белези са:</p><ul><li>относителна <strong>ритмичност</strong> и <strong>мономорфност</strong> на строежа;</li><li>липса на изразен клетъчен атипизъм;</li><li>липса на обичайна митотична активност;</li><li>оскъдна, богато васкуларизирана строма.</li></ul><p>Нормалният паренхим в съседство с аденома обикновено е <strong>атрофичен</strong>.</p><p>Рядко в надбъбречните жлези могат да се развият и <strong>мезенхимни тумори</strong>, като:</p><ul><li>ангиоми;</li><li>фиброми;</li><li>ангиолейоми.</li></ul><h3>Злокачествени тумори на надбъбречната кора</h3><p><strong>Карциномите на надбъбречната кора</strong> са редки новообразувания. Най-често се развиват между <strong>20- и 50-годишна възраст</strong>.</p><p>Макроскопски, в сравнение с аденомите, те достигат по-големи размери — до <strong>20 cm</strong> в диаметър. Обикновено имат възловидна или лобулирана форма, а по срезната повърхност се виждат:</p><ul><li><strong>некрози</strong>;</li><li><strong>кръвоизливи</strong>.</li></ul><p>Микроскопските и структурните белези на карциномите не могат надеждно да определят <strong>хормоналната активност</strong> на тумора.</p><p>Метастазирането може да се осъществи по:</p><ul><li>лимфен път;</li><li>хематогенен път.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Тумори на медуларната част на надбъбречните жлези</h2><p>Туморите на <strong>медуларната част</strong> на надбъбречната жлеза, както и на извъннадбъбречната <strong>хромафинна тъкан</strong>, отразяват етапите на диференциация на клетки с произход от <strong>невралния гребен</strong>.</p><p>Тези клетки участват в образуването на:</p><ul><li>симпатиковите ганглии;</li><li>надбъбречната медула;</li><li>хромафинната тъкан.</li></ul><h3>Невробластом</h3><p><strong>Невробластомът</strong> е един от най-честите злокачествени тумори в ранна детска възраст.</p><p>В <strong>50–70%</strong> от случаите е локализиран в надбъбречните жлези, но може да се развие навсякъде, където има структури на <strong>симпатиковата нервна система</strong>:</p><ul><li>торакално;</li><li>абдоминално;</li><li>в областта на шията.</li></ul><h3>Феохромоцитом</h3><p><strong>Феохромоцитомът</strong> е рядък тумор на хромафинната тъкан с характерни морфологични и функционални особености.</p><p>Когато туморът се развива извън надбъбрека от хромафинни елементи, разположени в други части на тялото, се означава като <strong>параганглиом</strong>.</p><p>Дори при малки размери феохромоцитомът може да секретира различни количества:</p><ul><li><strong>норадреналин</strong>;</li><li><strong>адреналин</strong>.</li></ul><p>Това води до развитие на <strong>надбъбречно-симпатикусов синдром</strong>, най-характерната проява на който е <strong>артериална хипертония</strong>. В урината се откриват <strong>катехоламинови деривати</strong>.</p><h4>Макроскопски промени</h4><p>Феохромоцитомът обикновено представлява добре отграничена овална маса с размери <strong>1–15 cm</strong> в диаметър.</p><p>На срез туморът има:</p><ul><li>кафяв или сивкав цвят;</li><li>понякога кистични кухини.</li></ul><h4>Микроскопски промени</h4><p>Въпреки клетъчния <strong>плеоморфизъм</strong>, в повечето случаи феохромоцитомът има доброкачествено протичане.</p><p>Инфилтрацията на капсулата или съдовете не е сигурен критерий за малигненост.</p><p>Единственият обективен и сигурен критерий за злокачественост са <strong>метастазите</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Хипоадренализъм</h2><h3>Хронична надбъбречна недостатъчност</h3><p><strong>Хроничната надбъбречна недостатъчност</strong>, или <strong>хипокортицизъм / болест на Addison</strong>, настъпва при разрушаване на поне <strong>80–90%</strong> от надбъбречните жлези. Развива се <strong>кортикомедуларна инсуфициенция</strong>, като преобладават проявите от страна на засегнатия <strong>кортекс</strong>. </p><h4>Етиология</h4><p>Най-честата причина е <strong>туберкулозата</strong>. Други причини са:</p><ul><li>масивни двустранни туморни метастази;</li><li><strong>амилоидоза</strong>;</li><li>атрофия след продължително лечение с кортикостероиди;</li><li><strong>идиопатична надбъбречна атрофия</strong>, свързана с циркулиращи антитела срещу надбъбречни антигени.</li></ul><h4>Морфогенеза</h4><p>Деструктивните процеси обхващат двете надбъбречни жлези и водят до <strong>тотална надбъбречна инсуфициенция</strong>.</p><p>Отпада секрецията на трите основни групи надбъбречни хормони:</p><ul><li><strong>минералкортикоиди</strong>;</li><li><strong>глюкокортикоиди</strong>;</li><li><strong>надбъбречни андрогени</strong>.</li></ul><p>Повечето промени при хипокортицизма са резултат от комбиниран <strong>минерало- и глюкокортикоиден дефицит</strong>.</p><h4>Клинична картина</h4><p>Класическата тетрада на <strong>Addison</strong> включва:</p><ol><li><strong>адинамия</strong>;</li><li><strong>хипотония</strong>;</li><li>гастроинтестинални нарушения;</li><li><strong>меланодермия</strong>.</li></ol><h4>Макроскопски промени</h4><p>Надбъбречните жлези са силно <strong>атрофични</strong>, сбръчкани и трудно се откриват. Коровият слой е силно изтънен, докато медулата може да изглежда непроменена.</p><p>При туберкулозно увреждане се наблюдават:</p><ul><li>жълтеникаво-белезникави огнища на <strong>казеозна некроза</strong>;</li><li>участъци на <strong>фиброза</strong> и <strong>хиалиноза</strong>;</li><li>отлагане на калциеви соли.</li></ul><p>При вродена хипоплазия се установява силна редукция главно на:</p><ul><li><strong>zona fasciculata</strong>;</li><li><strong>zona reticularis</strong>.</li></ul><p>В <strong>zona fasciculata</strong> се редуцират липоидните включвания, а в <strong>zona reticularis</strong> се натрупва <strong>липофусцин</strong>.</p><h4>Пигментни и органни промени</h4><p>Нарушената пигментна обмяна се дължи на повишена секреция на <strong>MSH</strong> и <strong>ACTH</strong>, вследствие на намалена кортизолова секреция.</p><p>Тя се проявява с обилно отлагане на <strong>меланин</strong> в:</p><ul><li>базалния слой на епидермиса;</li><li>съединителнотъканните елементи на дермата.</li></ul><p>Във вътрешните органи се наблюдава <strong>атрофия</strong>, особено изразена в сърцето и кръвоносните съдове.</p><p>В черния дроб се развива <strong>интерстициален реактивен хепатит</strong>, а в хепатоцитите се натрупва <strong>липофусцин</strong>.</p><p>В панкреаса настъпват дегенеративни промени в <strong>β-клетките</strong> на инсуларния апарат и се увеличава количеството на <strong>α-клетките</strong>. Между и около Лангерхансовите острови разраства съединителна тъкан. Тези промени обуславят развитието на диабет при болестта на Addison — <strong>бронзов диабет</strong>.</p><p>Лигавицата на стомаха е <strong>атрофична</strong>, а лимфните фоликули в целия стомашно-чревен тракт са хиперплазирали.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h3>Остра надбъбречна недостатъчност</h3><p><strong>Острата надбъбречна недостатъчност</strong> може да се развие в три основни ситуации:</p><ol><li>При стресови състояния, които предизвикват <strong>криза</strong> при болни с хронична болест на Addison.</li><li>При прекалено бързо намаляване на стероидите при пациенти с потиснати надбъбречни жлези след хронично стероидно лечение или при недостатъчно повишаване на заместителните стероиди по време на стрес след двустранна адреналектомия.</li><li>При масивно разрушаване на надбъбреците при здрави индивиди, свързано с кръвоизлив — <strong>надбъбречна апоплексия</strong>.</li></ol><p>При новородени надбъбреците са особено предразположени към кръвоизлив поради относително големия си размер, нежните медуларни венозни синуси и слабо развитите им мускулни стени. Допълнителен фактор е честата липса на <strong>протромбин</strong> в първите дни след раждането.</p><p>При възрастни кръвоизливното разрушаване на надбъбреците най-често е свързано с <strong>ДИК синдром</strong> при менингококов сепсис — <strong>синдром на Waterhouse–Friderichsen</strong>.</p><h4>Микроскопски промени</h4><p>При остра надбъбречна недостатъчност се наблюдават:</p><ul><li>тежки дегенеративни и атрофични изменения в <strong>zona fasciculata</strong> и <strong>zona reticularis</strong>;</li><li>огнищни кръвоизливи;</li><li>масивни апоплексии;</li><li>възпалителни инфилтрати;</li><li>обширни цикатрикси, заместващи функционалния паренхим на кората.</li></ul><p>Острата надбъбречна недостатъчност може да завърши с внезапна смърт от <strong>остра циркулаторна слабост</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Хиперфункция на надбъбречната кора</h2><p><strong>Хиперадренализмът</strong> е свързан със свръхпродукция на кортикостероиди от надбъбречната кора.</p><p>Основните групи кортикостероиди са:</p><ul><li><strong>глюкокортикоиди</strong>;</li><li><strong>минералкортикоиди</strong>;</li><li><strong>полови стероиди</strong>.</li></ul><p>Съответно се разграничават три основни хиперадренални синдрома:</p><ol><li><strong>Синдром на Cushing</strong> — излишък на кортизол.</li><li><strong>Алдостеронизъм</strong> — свръхпродукция на алдостерон.</li><li><strong>Адреногенитални синдроми</strong> — излишък на полови стероиди.</li></ol><p>Възможни са и <strong>смесени синдроми</strong>.</p><h3>Първичен алдостеронизъм</h3><p><strong>Първичният алдостеронизъм</strong>, или <strong>синдром на Conn</strong>, се развива при повишена продукция на <strong>алдостерон</strong> от <strong>zona glomerulosa</strong> на надбъбречната кора.</p><h4>Морфогенеза</h4><p>Алдостеронът действа върху дисталните бъбречни тубули, като:</p><ul><li>увеличава задръжката на <strong>натрий</strong>;</li><li>повишава елиминирането на <strong>калий</strong>.</li></ul><p>Нарушената електролитна обмяна води до промени в различни органи и системи, проявени с:</p><ul><li><strong>артериална хипертония</strong>;</li><li><strong>мускулна слабост</strong>;</li><li><strong>невропатия</strong>;</li><li><strong>хипогликемия</strong>;</li><li><strong>полиурия</strong>;</li><li><strong>полидипсия</strong>.</li></ul><h4>Етиология</h4><p>Най-честата причина е доброкачествен хормонално активен тумор — <strong>алдостером</strong>, произхождащ от клетките на <strong>zona glomerulosa</strong>. По-рядко причината е хиперплазия на този слой.</p><h4>Макроскопски промени</h4><p><strong>Алдостеромът</strong> е тумор с размер <strong>1–5 cm</strong>, жълт на цвят, изграден от големи светли клетки, съдържащи липиди. Почти не малигнизира.</p><p>Най-тежките органни промени са в сърцето, където в миофибрите се развиват <strong>огнищни некрози</strong>.</p><p>В бъбреците, коронарните и мозъчните артерии се установяват тежки <strong>атеросклеротични изменения</strong>.</p><p>В черния дроб се наблюдава <strong>белтъчна</strong> или <strong>мастна дегенерация</strong> на хепатоцитите.</p><p>В епителните клетки на проксималните сегменти на бъбречните извити каналчета се развива тежка <strong>хидропична дистрофия</strong> със:</p><ul><li>задебеляване на базалната мембрана;</li><li>некроза;</li><li>отлагане на калций.</li></ul><h3>Адреногенитален синдром</h3><p><strong>Адреногениталният синдром</strong> се характеризира с увеличена продукция на стероидни хормони с <strong>андрогенно</strong>, по-рядко <strong>естрогенно</strong>, действие от коровия слой на надбъбречните жлези.</p><h4>Етиология</h4><p>Заболяването е <strong>генетично обусловено</strong> и може да засегне няколко души от една фамилия. Унаследява се <strong>автозомно-рецесивно</strong>.</p><p>Дължи се на вродена <strong>хиперплазия на надбъбречната кора</strong>.</p><h4>Клинична картина</h4><p>Клинично се проявява с:</p><ul><li><strong>псевдохермафродитизъм</strong> при момичетата;</li><li>преждевременна <strong>вирилизация</strong> при момчетата.</li></ul><h4>Микроскопски промени</h4><p>В надбъбречните жлези се установява хиперплазия, главно на <strong>zona reticularis</strong>. Цитоплазмата на клетките съдържа обилно количество липиди.</p><p>В половите жлези се наблюдават:</p><ul><li>в тестисите — хиперплазия на <strong>Лайдиговите клетки</strong>;</li><li>в яйчниците — редукция на фоликулите и формиране на <strong>фоликуларни кисти</strong>.</li></ul><p>В предния дял на хипофизата е увеличено количеството на <strong>базофилните клетки</strong>.</p><p>Синдромът може да настъпи и при по-големи деца или възрастни вследствие на:</p><ul><li>хиперплазия на надбъбречната кора;</li><li>аденоми;</li><li>карциноми;</li><li>хормонално активни тумори на яйчниците.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 134. Тиреоидити. Видове, морфологична характеристика. Хипотиреоидизъм.</h1><p><strong>Възпалителните заболявания на щитовидната жлеза</strong> — <strong>тиреоидити</strong> — представляват нееднородна група поражения на щитовидната жлеза. </p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Остър тиреоидит</h2><p><strong>Острият тиреоидит</strong> се среща изключително рядко.</p><h3>Етиология</h3><p>Дължи се на инфектиране на щитовидната жлеза от <strong>гноеродни бактерии</strong>, попаднали в нея:</p><ul><li>по съседство;</li><li>хематогенно при септични заболявания.</li></ul><h3>Морфология</h3><p>Макроскопски жлезата е леко увеличена, напрегната и оточна.</p><p>Микроскопски се наблюдава картина на:</p><ul><li><strong>серозно възпаление</strong>;</li><li>или <strong>гнойно възпаление</strong>.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Грануломатозен тиреоидит на de Quervain</h2><p><strong>Грануломатозният тиреоидит на de Quervain</strong> — <strong>thyroiditis granulomatosa</strong> — се развива по-често при жени.</p><h3>Етиология</h3><p>Смята се, че се дължи на <strong>вирусна инфекция</strong> на щитовидната жлеза. Среща се по-често през студените сезони, когато са по-чести катаралните прояви на горните дихателни пътища.</p><h3>Морфология</h3><p>Макроскопски жлезата е умерено и асиметрично увеличена, с плътна консистенция. На срез се виждат малки белезникави поленца.</p><p>Микроскопски в началото се установява <strong>деструкция на фоликулите</strong>, а впоследствие — възпалителен инфилтрат, съставен от:</p><ul><li>лимфоцити;</li><li>плазматични клетки;</li><li><strong>туберкулоподобни грануломи</strong>.</li></ul><p>Грануломите са изградени от хистиоцити и гигантски клетки, подобни на <strong>Лангхансови клетки</strong>. В някои от тях се открива фагоцитиран <strong>колоид</strong>, а в центъра на грануломите също има колоид.</p><p>С времето се развива изразена <strong>фиброза на стромата</strong> и регенераторни процеси с новообразувани фоликули в островите от интерфоликуларен епител.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Хроничен лимфоматозен тиреоидит на Hashimoto</h2><p><strong>Хроничният лимфоматозен тиреоидит на Hashimoto</strong> е автоимунно заболяване, описано през <strong>1912 г.</strong>. Среща се и като <strong>лимфоматозна струма</strong>, поради видимата замяна на тиреоидния паренхим от лимфоидни клетки.</p><p>Той е първата описана типична <strong>органоспецифична автоимунна болест</strong>. Засяга предимно женския пол и най-често се проявява между <strong>30–50-годишна възраст</strong>.</p><h3>Макроскопски промени</h3><p>Щитовидната жлеза е дифузно увеличена, със запазена лобулираност и плътноеластична консистенция.</p><p>Капсулата е интактна и много рядко има срастване с околните тъкани. Срезната повърхност е <strong>сивобелезникава</strong>.</p><p>Въпреки че макроскопски може да наподобява неопластичен процес, <strong>симетричността</strong> и <strong>дифузното обхващане</strong> на жлезата са против такава диагноза.</p><h3>Микроскопски промени</h3><p>Голяма част от жлезната тъкан е заместена от:</p><ul><li>лимфоцити;</li><li>плазмоцити;</li><li>имунобласти;</li><li>макрофаги.</li></ul><p>Характерни са многобройни <strong>лимфни фоликули</strong>, повечето със <strong>зародишен център</strong>.</p><p>Инфилтратите раздалечават тиреоидните фоликули. В някои участъци фоликулите са със запазени морфологични белези на повишена функционална активност — <strong>хашитоксикоза</strong>.</p><p>В други участъци фоликулите са намалени по размер, на места без колоид. Тапициращите клетки са предимно кубични, с обилна гранулирана еозинофилна цитоплазма и понякога изразен ядрен атипизъм — <strong>онкоцити</strong>.</p><p>Ултраструктурно <strong>онкоцитите</strong> съдържат голямо количество митохондрии и почти нямат протеинсинтезиращи органели.</p><p>При по-продължително протичане настъпва деструкция на жлезния паренхим, фрагментиране на базалната мембрана и разрастване на съединителна тъкан.</p><p>Тези промени са в основата на <strong>хипофункцията</strong> и <strong>микседема</strong> при болните.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Инвазивен фиброзен тиреоидит на Riedel</h2><p><strong>Тиреоидитът на Riedel</strong> — <strong>struma fibrosa</strong> — е рядко заболяване, което започва незабелязано и обикновено протича хронично.</p><h3>Етиология</h3><p>Етиологията е неизвестна. Някои автори го приемат като краен стадий в развитието на различни форми на тиреоидит, особено тиреоидит на Hashimoto.</p><p>Срещу това стоят данните, че фиброзният тиреоидит не се съпровожда от значително повишаване на титъра на тиреоидните антитела или от изобилна лимфоидна инфилтрация.</p><h3>Морфология</h3><p>Макроскопски жлезата е силно плътна — описва се като твърда „като дърво“. Тя е масивно сраснала с околните тъкани, изглежда деформирана и може да наподобява неопластичен процес.</p><p>Микроскопски се вижда обилно прорастване на плътна <strong>хиалинизирана колагенна тъкан</strong> сред жлезния паренхим.</p><p>Сред фиброзната тъкан има оскъдни лимфоцитни инфилтрати. Тиреоидните фоликули са единични, атрофични, покрити с нисък епител, на места с <strong>онкоцитна трансформация</strong>.</p><p>Заболяването може да се съчетае с:</p><ul><li>ретроперитонеална фибросклероза;</li><li>медиастинална фибросклероза;</li><li>белодробна фибросклероза.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Хипотиреоидизъм</h2><p><strong>Хипотиреоидизмът</strong> представлява функционална недостатъчност на щитовидната жлеза, при която е намалена продукцията на тиреоидни хормони.</p><h3>Етиология</h3><p>В повечето случаи — <strong>90–95%</strong> — заболяването се дължи на патологични процеси в самата <strong>щитовидна жлеза</strong>, които понижават продукцията на хормони.</p><p>Причини за хипотиреоидизъм могат да бъдат:</p><ul><li><strong>тиреоидектомия</strong>;</li><li>лечение с <strong>тиреостатици</strong>;</li><li>деструктивни поражения на жлезата;</li><li><strong>дисгенезия</strong> и други вродени нарушения.</li></ul><h3>Кретенизъм</h3><p><strong>Кретенизмът</strong>, или <strong>вроден микседем</strong>, се развива, когато тиреоидната недостатъчност възникне още по време на ембрионалното развитие или в ранното детство.</p><h4>Етиология</h4><p>Заболяването може да бъде свързано с:</p><ul><li>вродена липса на щитовидна жлеза — <strong>атиреоза</strong>;</li><li><strong>хипоплазия</strong> на щитовидната жлеза;</li><li><strong>йодна недостатъчност</strong>, особено в ендемични райони;</li><li>ензимни дефекти в метаболизма на йода;</li><li>наличие на <strong>антитироксин-антитела</strong> у майката.</li></ul><h4>Клинична картина</h4><p>Симптомите обикновено се проявяват <strong>4–6 седмици след раждането</strong>.</p><p>Характерни са:</p><ul><li>затруднена <strong>осификация</strong>;</li><li>късна поява на ядрата на вкостяване;</li><li>забавено психично развитие;</li><li>силно забавено поникване на зъбите.</li></ul><p>Поникването на зъбите започва около <strong>третата година</strong> и може да продължи до около <strong>20-годишна възраст</strong>. Зъбите поникват в обратен ред — първо кучешките, след това резците. Смяната на млечните зъби също закъснява.</p><h3>Микседем</h3><p><strong>Микседемът</strong> се развива при функционална недостатъчност на щитовидната жлеза в по-късна детска възраст или при възрастни.</p><h4>Клинична картина</h4><p>При микседем процесите на обмяната на веществата са редуцирани, а телесната температура е понижена.</p><p>Подкожната тъкан е оточна поради задръжка на <strong>натрий</strong> и натрупване на слузна материя в кожата и подкожието. Това придава характерния оточен вид на болните.</p><p>Неврологичните и психичните прояви са резултат от недостига на тиреоидни хормони и влиянието му върху <strong>ЦНС</strong>. Наблюдават се:</p><ul><li>сънливост;</li><li>нарушения в паметта;</li><li><strong>деменция</strong>.</li></ul><p>Слузна материя се натрупва и във вътрешните органи, главно в:</p><ul><li>сърцето;</li><li>бъбреците;</li><li>панкреаса.</li></ul><p>Често се установяват:</p><ul><li><strong>хидроперикард</strong>;</li><li>прогресираща сърдечна недостатъчност;</li><li><strong>микседематозна миопатия</strong> в скелетната мускулатура.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 135. Тиреотоксикоза. Морфологична характеристика.</h1><p><strong>Хипертиреоидизмът</strong> е състояние, клинично известно още като <strong>тиреотоксикоза</strong> или <strong>Базедова болест</strong> — <strong>morbus Basedowi</strong>.</p><h2>Морфология на щитовидната жлеза</h2><h3>Макроскопски промени</h3><p>Щитовидната жлеза е:</p><ul><li>дифузно увеличена;</li><li>с червеникав цвят;</li><li>със сочна срезна повърхност.</li></ul><h3>Микроскопски промени</h3><p>Хистологично жлезата запазва лобуларния си строеж, но фоликулите са с различна големина.</p><p>Характерни са:</p><ul><li>висок цилиндричен фоликуларен епител;</li><li>чести папиларни разраствания;</li><li>неправилна звездовидна форма на фоликулните лумени;</li><li>оскъден, разреден и бледорозов колоид;</li><li>многобройни резорбционни вакуоли по периферията на колоида.</li></ul><p>Стромата се характеризира с:</p><ul><li>пълнокръвие на съдовете;</li><li>лимфоцитни инфилтрати;</li><li>често формиране на лимфни фоликули с герминативни центрове.</li></ul><h2>Органни промени</h2><h3>Сърце</h3><p>Макроскопски се наблюдават:</p><ul><li>хипертрофия на лявата камера;</li><li>дилатация на лявата камера.</li></ul><p>Микроскопски се установяват:</p><ul><li>мастна инфилтрация в отделни групи мускулни влакна;</li><li>малки огнища на некроза;</li><li>интерстициален оток;</li><li>лимфоцитоподобни инфилтрати;</li><li>по-късно — интерстициална фиброза.</li></ul><p>Тези промени се означават като <strong>cor thyreotoxicum</strong>.</p><h3>Черен дроб</h3><p>В черния дроб се установяват:</p><ul><li>мастна инфилтрация;</li><li>по-рядко — некротични огнища в централните части на делчетата, главно под капсулата;</li><li>възможно разрастване на фиброзна съединителна тъкан в тези участъци.</li></ul><h3>Централна нервна система</h3><p>Макроскопски в нервната система могат да се наблюдават <strong>кръвоизливи в дъното на четвъртия вентрикул</strong>.</p><p>Микроскопски в сивите ядра се установяват <strong>дегенеративни промени</strong>.</p><h2>Други промени</h2><p>Често се наблюдава <strong>хиперплазия на лимфните възли</strong>. В някои случаи тя се съчетава с:</p><ul><li>хиперплазия на тимуса;</li><li>атрофия на надбъбречните жлези.</li></ul><p>Поради повишената консумация на кислород при заболяването намаляват:</p><ul><li>гликогеновите депа;</li><li>мастните депа в организма.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><br><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 136. Тумори на щитовидната жлеза. Морфологична характеристика.</h1><p>Най-честите тумори на <strong>щитовидната жлеза</strong> са <strong>епителните тумори</strong>, които могат да бъдат:</p><ul><li><strong>доброкачествени</strong> — аденоми;</li><li><strong>злокачествени</strong> — карциноми.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Доброкачествени тумори — аденоми</h2><h3>Макроскопски промени</h3><p><strong>Аденомите</strong> са единични или множествени възли с размери около <strong>2–6 cm</strong> в диаметър.</p><p>Най-често са добре ограничени от околната жлезна тъкан чрез <strong>фиброзна капсула</strong>.</p><p>На цвят са <strong>жълтокафяви</strong>. Понякога в тях се наблюдават:</p><ul><li>кръвоизливи;</li><li>разрастване на фиброзна тъкан;</li><li>отлагане на калциеви соли.</li></ul><h3>Микроскопски промени</h3><p>Клетките могат да бъдат подредени като:</p><ul><li>солидни трабекули — <strong>ембрионален аденом</strong>;</li><li>малки фоликули — <strong>фетален аденом</strong>;</li><li>струпвания от малки фоликули, съдържащи колоид — <strong>колоиден аденом</strong>.</li></ul><p>Тъй като всички аденоми съдържат фоликули с различни размери и в различни пропорции, те могат общо да се означат като <strong>фоликуларни аденоми</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Злокачествени тумори на щитовидната жлеза</h2><h3>Честота и разпространение</h3><p><strong>Карциномите на щитовидната жлеза</strong> са сравнително редки. Жените се засягат по-често от мъжете, със съотношение <strong>жени : мъже = 3 : 1</strong>.</p><h3>Класификация</h3><p>Различават се няколко основни морфологични вида <strong>тиреоиден карцином</strong>, всеки със свои биологични и клинични особености:</p><ul><li><strong>папиларен карцином</strong>;</li><li><strong>фоликуларен карцином</strong>;</li><li><strong>медуларен карцином</strong>;</li><li><strong>недиференциран / анапластичен карцином</strong>.</li></ul><h3>Папиларен карцином</h3><p><strong>Папиларният карцином</strong> е най-честата форма на злокачествен тумор на щитовидната жлеза както при деца, така и при възрастни.</p><h4>Макроскопски промени</h4><p>Размерите варират от микроскопски огнища, открити случайно, до възли с диаметър до <strong>10 cm</strong>.</p><p>Значителна част от тези тумори имат <strong>мултифокално разпространение</strong> в жлезата.</p><h4>Микроскопски промени</h4><p>Преобладават разклонени <strong>папили</strong>, покрити с кубичен или цилиндричен епител.</p><p>Характерни са:</p><ul><li>относително големи ядра;</li><li>бедна на хроматин ядрена структура;</li><li>ядра с вид на <strong>матово стъкло</strong>;</li><li>калциеви отлагания в папилите — <strong>псамомни телца</strong>.</li></ul><p><strong>Псамомните телца</strong> рядко се срещат при други тиреоидни неоплазми, поради което насочват към диагнозата <strong>папиларен карцином</strong>.</p><p>Папиларният карцином има предимно <strong>местен растеж</strong> и метастазира по-късно, главно в:</p><ul><li>шийните лимфни възли;</li><li>по-рядко — белите дробове;</li><li>по-рядко — костите.</li></ul><h3>Фоликуларен карцином</h3><p><strong>Фоликуларният карцином</strong> съставлява около <strong>25%</strong> от всички тиреоидни неоплазми и е биологично по-агресивен от папиларния карцином.</p><h4>Микроскопски промени</h4><p>Туморът може да показва значителни различия в размера и диференциацията на фоликулите.</p><p>Някои тумори имат предимно <strong>трабекуларен строеж</strong> с малки абортивни фоликули, а други са изградени от добре оформени фоликули, съдържащи <strong>колоид</strong>.</p><p>За разлика от папиларния карцином, <strong>фоликуларният карцином</strong> има изразена склонност към:</p><ul><li>проникване в кръвоносните съдове;</li><li><strong>хематогенно метастазиране</strong>.</li></ul><h3>Медуларен карцином</h3><p><strong>Медуларният карцином</strong> произлиза от <strong>калцитонин-продуциращите C-клетки</strong> на щитовидната жлеза.</p><p>Той е типичен представител на <strong>невроендокринните неоплазми</strong>.</p><p>Характерни белези са:</p><ol><li>наличие на <strong>амилоид</strong> в стромата;</li><li>генетична предразположеност;</li><li>секреция на <strong>калцитонин</strong> и други пептиди.</li></ol><h4>Честота</h4><p>Медуларният карцином е рядък и съставлява около <strong>5–7%</strong> от тиреоидните карциноми.</p><h4>Микроскопски промени</h4><p>Хистологично туморът наподобява недиференциран малигнен тумор.</p><p>Туморните клетки могат да бъдат източени или кръгли, със сравнително големи ядра и умерен плеоморфизъм. Те са подредени в:</p><ul><li>гнезда;</li><li>повлекла.</li></ul><p>Понякога могат да се открият:</p><ul><li>псевдорозеткови структури;</li><li>псевдопапиларни структури.</li></ul><p>Фоликули не се формират.</p><p>Между повлеклата от туморни клетки има различно количество строма, често представена от хомогенна хиалиноподобна розова материя с качества на <strong>амилоид</strong>.</p><p>Амилоидът произхожда от неопластичните <strong>C-клетки</strong> и представлява изменени <strong>калцитонинови молекули</strong>.</p><h3>Недиференциран / анапластичен карцином</h3><p><strong>Недиференцираният</strong>, или <strong>анапластичен карцином</strong>, е изключително малигнен тумор.</p><p>Съставлява около <strong>10–15%</strong> от всички тиреоидни карциноми.</p><p>Развива се обикновено при възрастни хора след <strong>60-годишна възраст</strong>, предимно при жени.</p><h4>Макроскопски промени</h4><p>Туморът се представя като плътна маса, която понякога заема и двата дяла на щитовидната жлеза.</p><p>Често е прираснал към съседните структури.</p><p>На срез има <strong>сивобелезникав цвят</strong>.</p><h4>Микроскопски промени</h4><p>Основните белези, които показват анапластичния характер на карцинома, са:</p><ul><li>изразен <strong>клетъчен атипизъм</strong>;</li><li>липса на структурна диференциация;</li><li>инфилтрация на околните тъкани;</li><li>инфилтрация в кръвоносни съдове;</li><li>огнища на <strong>некроза</strong>.</li></ul><p>Тези промени подчертават агресивното и бързо нарастване на този тип неоплазма.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 137. Заболявания на паращитовидната жлеза. Хипер- и хипопаратиреоидизъм.</h1><p>Морфологичните нарушения на <strong>паращитовидните жлези</strong> се проявяват с две основни функционални състояния:</p><ul><li><strong>хиперпаратиреоидизъм</strong>;</li><li><strong>хипопаратиреоидизъм</strong>.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Хиперпаратиреоидизъм</h2><p>Различават се две основни форми:</p><ol><li><strong>Първичен хиперпаратиреоидизъм</strong>.</li><li><strong>Вторичен хиперпаратиреоидизъм</strong>.</li></ol><h3>Първичен хиперпаратиреоидизъм</h3><p><strong>Първичният хиперпаратиреоидизъм</strong> възниква при увреждания, присъщи на самите паращитовидни жлези. Характеризира се със свръхпродукция на <strong>паратхормон</strong>, водеща до <strong>хиперкалциемия</strong> и <strong>хипофосфатемия</strong>.</p><p>Най-често се развива на основата на:</p><ul><li><strong>аденом</strong> от главните клетки на една от паращитовидните жлези;</li><li><strong>хиперплазия</strong> на четирите паращитовидни жлези.</li></ul><p>Известен е още като <strong>болест на Recklinghausen</strong> или <strong>osteodystrophia generalisata fibrosa cystica</strong>.</p><p>Основните биохимични белези са:</p><ul><li>повишени серумни нива на <strong>паратхормон</strong>;</li><li><strong>хиперкалциемия</strong>;</li><li><strong>хипофосфатемия</strong>;</li><li>повишена екскреция на <strong>калций</strong> с урината.</li></ul><h4>Морфогенеза</h4><p>Продължителната паратиреоидна хиперфункция води до усилена <strong>деминерализация</strong> и рязко преустройство на архитектониката на дългите и плоските кости.</p><p>Най-силно се засягат:</p><ul><li>тазовите кости;</li><li>бедрените кости;</li><li>костите на черепа;</li><li>ребрата;</li><li>прешлените.</li></ul><p>В костите настъпват <strong>размекване</strong> и <strong>резорбция</strong> на костното вещество. След това се развива пролиферация на ендоста и новообразуване на <strong>остеоидно вещество</strong>, което замества резорбираната костна тъкан.</p><p>Минерализацията на остеоида е нарушена — протича бавно и неправилно. В резултат костта остава незряла, фиброзна и без нормално формирани костни гредички.</p><p>В отделни участъци фиброзната тъкан:</p><ul><li>изпълва кистични кухини;</li><li>оформя туморовидни образувания;</li><li>съдържа множество гигантски клетки тип <strong>остеокласти</strong>;</li><li>съдържа богата съдова мрежа.</li></ul><p>В засегнатите зони често се откриват <strong>кръвоизливи</strong> и обилно количество <strong>хемосидерин</strong>.</p><h4>Калциеви отлагания и органни промени</h4><p>Големите количества калций, извлечени от костите, се отлагат в:</p><ul><li>белите дробове;</li><li>миокарда;</li><li>стените на кръвоносните съдове;</li><li>меките тъкани.</li></ul><p>В бъбреците се развива <strong>нефрокалциноза</strong> — импрегниране на бъбречния паренхим с калциеви соли. Тя може да се усложни с <strong>пиелонефрит</strong> и <strong>бъбречна недостатъчност</strong>, която от своя страна може да доведе до <strong>вторичен хиперпаратиреоидизъм</strong>.</p><p>Поради високото съдържание на калций в урината се създават условия за образуване на <strong>бъбречни камъни</strong>.</p><p>За хиперпаратиреоидизма е характерно и развитието на язви, най-често в <strong>дванадесетопръстника</strong>. Предполага се, че значение имат:</p><ul><li><strong>хиперкалциемията</strong>;</li><li>калцификацията на кръвоносните съдове;</li><li>нарушеното кръвоснабдяване и трофика на лигавицата;</li><li>възможно директно действие на <strong>паратхормона</strong> върху лигавицата.</li></ul><h3>Вторичен хиперпаратиреоидизъм</h3><p><strong>Вторичният хиперпаратиреоидизъм</strong> също е свързан със свръхпродукция на <strong>паратхормон</strong>, но се развива при функционално противопоставяне на таргетните тъкани спрямо действието на хормона.</p><p>При него физиологичните ефекти на паратхормона са частично блокирани, което води до:</p><ul><li><strong>хипокалциемия</strong>;</li><li><strong>хиперфосфатемия</strong>.</li></ul><p>Ниските серумни нива на калций стимулират паращитовидните жлези и с времето индуцират <strong>хиперпластични промени</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Хипопаратиреоидизъм</h2><p><strong>Хипопаратиреоидизмът</strong> представлява недостатъчност на паращитовидните жлези и се среща сравнително рядко.</p><p>Най-често възниква след <strong>тиреоидектомия</strong>, когато заедно с щитовидната жлеза бъдат отстранени и паращитовидните жлези.</p><p>Други възможни промени са:</p><ul><li>атрофия;</li><li>фиброза вследствие на хроничен възпалителен процес.</li></ul><h3>Морфогенеза</h3><p>Основна роля има абсолютният или относителният дефицит на <strong>паратхормон</strong>, който води до:</p><ul><li><strong>хипокалциемия</strong>;</li><li><strong>хиперфосфатемия</strong>.</li></ul><p>Тези промени са свързани с:</p><ul><li>нарушено всмукване на калций в червото;</li><li>понижена мобилизация на калций от костите;</li><li>относително намалена реабсорбция на калций в бъбречните каналчета.</li></ul><p>Отрицателният калциев и положителният фосфатен баланс нарушават електролитното равновесие. Променя се съотношението:</p><ul><li><strong>калций / фосфор</strong>;</li><li><strong>натрий / калий</strong>.</li></ul><p>Това води до универсално нарушение на пропускливостта на клетъчните мембрани, включително в нервните клетки, и до промени в процесите на поларизация в областта на синапсите.</p><h3>Клинична картина</h3><p>Основна последица е повишената <strong>нервно-мускулна възбудимост</strong> и общата вегетативна реактивност.</p><p>Клинично това води до <strong>тетания</strong>, проявена с тежки мускулни гърчове.</p><p>При продължителен хипопаратиреоидизъм се развиват трофични промени:</p><ul><li>промени в кожата;</li><li>чупливост и отпадане на ноктите;</li><li><strong>катаракта</strong> при около <strong>50%</strong> от болните;</li><li><strong>остеосклероза</strong>, особено в кортикалиса на тръбестите кости</li></ul>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.js\"></script>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/contrib/auto-render.min.js\"></script>\n<script>\nrenderMathInElement(document.body, {\n  delimiters: [\n    {left: '$$', right: '$$', display: true},\n    {left: '$', right: '$', display: false},\n    {left: '\\\\[', right: '\\\\]', display: true},\n    {left: '\\\\(', right: '\\\\)', display: false}\n  ],\n  throwOnError: false\n});\n</script>\n</body>\n</html>";
